    return NextResponse.json({ error: 'Forbidden' }, { status: 403 })
  }

  // 3. Fetch transaction
  let transaction: Record<string, unknown> | null = null
  try {
    transaction = (await payload.findByID({
      collection: 'transactions',
      id,
      depth: 0,
      overrideAccess: true,
    })) as unknown as Record<string, unknown> | null
  } catch (err) {
